	[113] = {
		id = 113,
		sender = 'Misty',
		sender_en = 'Misty',
		subject = 'Notice for illegal discount top-up',
		subject_en = 'Notice for illegal discount top-up',
		subject_vn = 'Thông báo về việc nạp tiền giảm giá bất hợp pháp',
		subject_pt = 'Aviso sobre recarga com desconto ilegal',
		subject_th = 'ประกาศเกี่ยวกับการเติมเงินส่วนลดที่ผิดกฎหมาย',
		content = 'Dear trainers,\n  Recently we found that some trainer are using illegal third-party top-up method.\n  In order to maintain the fairness of the game, and ensure everyone\'s account safety,we will take action on trainers who using illegal third-party top-up.\n  1) Illegal recharge channels is unsecure for your personal information and your credit card.\n  2) If after using illegal third-party top-up and service provider refunds, you account will be banned.\n  3) We will not deal with any issue caused by using illegal third-party top-up method.\n  4) Your account may being stolen by illegal top-up service providers.\n  Please cherish your account and be aware of "discount" top-up scam.\n  Sincerely\n  Devs group',
		content_en = 'Dear trainers,\n  Recently we found that some trainer are using illegal third-party top-up method.\n  In order to maintain the fairness of the game, and ensure everyone\'s account safety,we will take action on trainers who using illegal third-party top-up.\n  1) Illegal recharge channels is unsecure for your personal information and your credit card.\n  2) If after using illegal third-party top-up and service provider refunds, you account will be banned.\n  3) We will not deal with any issue caused by using illegal third-party top-up method.\n  4) Your account may being stolen by illegal top-up service providers.\n  Please cherish your account and be aware of "discount" top-up scam.\n  Sincerely\n  Devs group',
		content_vn = 'Các nhà huấn luyện thân mến,\n  Gần đây chúng tôi phát hiện ra rằng một số nhà huấn luyện đang sử dụng phương thức nạp tiền của bên thứ ba bất hợp pháp.\n  Để duy trì sự công bằng của trò chơi và đảm bảo an toàn cho tài khoản của mọi người, chúng tôi sẽ có biện pháp đối với những nhà huấn luyện sử dụng phương thức nạp tiền của bên thứ ba bất hợp pháp.\n  1) Các kênh nạp tiền bất hợp pháp không an toàn cho thông tin cá nhân và thẻ tín dụng của bạn.\n  2) Nếu sau khi sử dụng phương thức nạp tiền của bên thứ ba bất hợp pháp và nhà cung cấp dịch vụ hoàn tiền, tài khoản của bạn sẽ bị cấm.\n  3) Chúng tôi sẽ không giải quyết bất kỳ vấn đề nào phát sinh do sử dụng phương thức nạp tiền của bên thứ ba bất hợp pháp.\n  4) Tài khoản của bạn có thể bị các nhà cung cấp dịch vụ nạp tiền bất hợp pháp đánh cắp.\n  Vui lòng quý trọng tài khoản của bạn và cảnh giác với lừa đảo nạp tiền "giảm giá".\n  Trân trọng\n  Nhóm phát triển',
		content_pt = 'Caros Treinadores,\n  Recentemente descobrimos que alguns treinadores estão usando métodos de recarga ilegais de terceiros.\n  Para manter a justiça do jogo e garantir a segurança da conta de todos, tomaremos medidas contra os treinadores que usam recargas ilegais de terceiros.\n  1) Canais de recarga ilegais não são seguros para suas informações pessoais e seu cartão de crédito.\n  2) Se após usar a recarga ilegal de terceiros e o provedor de serviços reembolsar, sua conta será banida.\n  3) Não trataremos de nenhum problema causado pelo uso de métodos de recarga ilegais de terceiros.\n  4) Sua conta pode ser roubada por provedores de serviços de recarga ilegais.\n  Por favor, valorize sua conta e esteja ciente de golpes de recarga com "desconto".\n  Atenciosamente\n  Grupo de Desenvolvedores',
		content_th = 'ถึงเหล่าเทรนเนอร์,\n  เมื่อเร็วๆ นี้เราพบว่ามีเทรนเนอร์บางคนใช้วิธีการเติมเงินจากบุคคลที่สามที่ผิดกฎหมาย\n  เพื่อรักษาความเป็นธรรมของเกมและรับประกันความปลอดภัยของบัญชีผู้ใช้ทุกคน เราจะดำเนินการกับเทรนเนอร์ที่ใช้การเติมเงินจากบุคคลที่สามที่ผิดกฎหมาย\n  1) ช่องทางการเติมเงินที่ผิดกฎหมายไม่ปลอดภัยสำหรับข้อมูลส่วนบุคคลและบัตรเครดิตของคุณ\n  2) หากหลังจากการใช้การเติมเงินจากบุคคลที่สามที่ผิดกฎหมายแล้วผู้ให้บริการทำการคืนเงิน บัญชีของคุณจะถูกแบน\n  3) เราจะไม่จัดการกับปัญหาใดๆ ที่เกิดจากการใช้วิธีการเติมเงินจากบุคคลที่สามที่ผิดกฎหมาย\n  4) บัญชีของคุณอาจถูกขโมยโดยผู้ให้บริการเติมเงินที่ผิดกฎหมาย\n  โปรดรักษาบัญชีของคุณและระวังการหลอกลวงการเติมเงิน "ลดราคา"\n  ขอแสดงความนับถือ\n  กลุ่มผู้พัฒนา'
	},
